def render_text(text, font_name='standard', width=80, justify='left'):
    """Render text using the specified font."""
    if font_name not in FONTS:
        print(f"Unknown font: {font_name}. Available: {', '.join(FONTS.keys())}", file=sys.stderr)
        sys.exit(1)

    font = FONTS[font_name]
    text = text.upper()

    # Get height from font
    if not text:
        return ''
    height = len(font.get(text[0], font.get('A', [''] * 5)))
    lines = [''] * height

    for i, ch in enumerate(text):
        ch_art = font.get(ch, font[' '])
        for row in range(height):
            if row < len(ch_art):
                lines[row] += ch_art[row]
            else:
                lines[row] += ' ' * len(font[' '][0]) if ' ' in font else '     '

    # Handle width
    result_lines = []
    for line in lines:
        rstrip_line = line.rstrip()
        if len(rstrip_line) > width:
            result_lines.append(rstrip_line[:width])
        elif justify == 'center':
            result_lines.append(rstrip_line.center(width))
        else:
            result_lines.append(rstrip_line)

    return '\n'.join(result_lines)


def list_fonts():
    """List available fonts."""
    print("\033[1mAvailable fonts:\033[0m")
    for name in FONTS:
        print(f"  \033[33m{name}\033[0m")


def main():
    parser = argparse.ArgumentParser(
        description='ASCII banner generator (figlet-style). Render text as ASCII art.',
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  figlet "Hello World"
  figlet --font block "EVOLVER"
  figlet --width 40 "Hi"
  figlet --list
  figlet --center "Centered"
        """,
    )
    parser.add_argument('text', nargs='*', help='Text to render')
    parser.add_argument('--font', '-f', choices=list(FONTS.keys()), default='standard',
                        help='Font style (default: standard)')
    parser.add_argument('--width', '-w', type=int, default=80, help='Max output width')
    parser.add_argument('--list', '-l', action='store_true', help='List available fonts')
    parser.add_argument('--center', '-c', action='store_true', help='Center the output')

    args = parser.parse_args()

    if args.list:
        list_fonts()
        return

    text = ' '.join(args.text) if args.text else ''
    if not text and not sys.stdin.isatty():
        try:
            text = sys.stdin.read().strip()
        except KeyboardInterrupt:
            text = ''

    if not text:
        parser.print_help()
        sys.exit(1)

    try:
        justify = 'center' if args.center else 'left'
        result = render_text(text, args.font, args.width, justify)
        print(result)
    except KeyboardInterrupt:
        print("\nAborted.", file=sys.stderr)
        sys.exit(1)
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == '__main__':
    main()
